id_unico_trx_alerta STRING  OPTIONS(description= 'Identificador único para la transacción asociada con la alerta o caso.'), 
num_coincidencias_analisis FLOAT64  OPTIONS(description= 'Número de coincidencias encontradas en el proceso de análisis de datos para una transacción específica.'), 
fecha_alta_alerta_adq_cio DATE  OPTIONS(description= 'Fecha de alta de la alerta o transacción en el sistema del Centro de Información Operacional (CIO) para el adquirente (ADQ).'), 
num_coincidencias_analisis_adq FLOAT64  OPTIONS(description= 'Número de coincidencias específicas encontradas durante el análisis realizado para un adquirente particular.'), 
tamanio_analisis_alerta_cio FLOAT64  OPTIONS(description= 'Tamaño de la transacción o el análisis de la alerta procesada por el CIO del adquirente, que puede estar relacionado con la cantidad de datos involucrados.'), 
num_trx_aprobadas_adq INT64  OPTIONS(description= 'Número de transacciones aprobadas para el adquirente (ADQ) tras el análisis de riesgo.'), 
ultimo_tiempo_evento_cio_adq STRING  OPTIONS(description= 'Último tiempo registrado para un evento o transacción procesada por el Centro de Información Operacional (CIO) del adquirente.'), 
num_dia_uso_servicio_adq INT64  OPTIONS(description= 'Número de días en que se ha utilizado el servicio o tarjeta del adquirente en relación con la transacción o alerta.'), 
tamano_cio_adq STRING  OPTIONS(description= 'Tamaño del Centro de Información Operacional (CIO) del adquirente, lo que puede estar relacionado con la infraestructura o capacidad de procesamiento.'), 
puntuacion_total_neural STRING  OPTIONS(description= 'Puntuación total calculada por un sistema de puntuación neural o basado en algoritmos de aprendizaje automático para evaluar el riesgo o la probabilidad de fraude.'), 
puntuacion_factores_riesgo STRING  OPTIONS(description= 'Puntuación que incluye diversos factores de riesgo evaluados para la transacción, incluyendo variables como la ubicación, la frecuencia y el comportamiento del cliente.'), 
puntuacion_total_adquirencia STRING  OPTIONS(description= 'Puntuación total de adquirencia, utilizada para evaluar el riesgo en función del comportamiento de los adquirentes en el proceso de pago.'), 
puntuacion_analisis_adq STRING  OPTIONS(description= 'Puntuación que asigna una prioridad al análisis de fraude o alertas por parte del adquirente, basada en la intervención de vigilancia.'), 
usuario_toma_alerta STRING  OPTIONS(description= 'Usuario que tomó la alerta por primera vez en el sistema para su análisis o resolución.'), 
fecha_toma_alerta DATE  OPTIONS(description= 'Fecha en que la alerta fue tomada por primera vez por un usuario para su investigación.'), 
hora_toma_alerta STRING  OPTIONS(description= 'Hora en la que la alerta fue tomada por primera vez, proporcionando un nivel de detalle temporal.'), 
mensaje_formato_envio_alerta STRING  OPTIONS(description= 'Mensaje o formato utilizado para el envío de la alerta, que puede ser un correo electrónico, notificación, o algún otro medio.'), 
nivel_prioridad__alerta_adq STRING  OPTIONS(description= 'Nivel de prioridad asignado a la investigación de la alerta o transacción por parte del adquirente (ADQ), para indicar la urgencia o gravedad de la situación.'), 
calificacion_adq_alerta_trx STRING  OPTIONS(description= 'Calificación asignada por el adquirente (ADQ) en relación con la alerta, transacción o comportamiento del cliente.'), 
puntuacion_dinamica_adq FLOAT64  OPTIONS(description= 'Puntuación dinámica asignada por el adquirente (ADQ), que puede ajustarse en tiempo real en función de ciertos parámetros de la transacción.'), 
proceso_encargado_trx_adq FLOAT64  OPTIONS(description= 'Proceso o entidad encargada de procesar las transacciones del adquirente.'), 
ind_condiciones_generan_alerta STRING  OPTIONS(description= 'Indicador de si las condiciones necesarias para generar la alerta han sido cumplidas, según las reglas de negocio o el sistema de monitoreo.'), 
campo_saltado_analisis_trx STRING  OPTIONS(description= 'Campo relacionado con el análisis de transacciones u operaciones que han sido "saltadas" o no consideradas en el proceso de análisis.'), 
record_source STRING NOT NULL OPTIONS(description= 'Dato de Auditoría: Descripción del aplicativo origen de los datos.'), 
load_date TIMESTAMP NOT NULL OPTIONS(description= 'Fecha y hora de inserción del registro en el modelo'), 
creation_user STRING NOT NULL OPTIONS(description= 'Usuario que crea el registro en la BD'), 
)
PARTITION BY process_date
OPTIONS (description ='Tabla historica que contiene la informacion historica mensual de las alertas adq', require_partition_filter = true);

